#include<bits/stdc++.h>
using namespace std;

int a[101][101],v[101],n,m;
int dfs(int x,int z){
	v[x]=1;
	int maxx=0;
	for(int i=1;i<=n;i++){
		if(a[x][i]!=0&&v[i]==0){
			maxx=max(maxx,dfs(i,x));
		}
	}
	v[x]=0;
	return maxx+a[x][z];
}
int main(){
	cin>>n>>m;
	for(int i=0;i<m;i++){
		int x,y,z;
		cin>>x>>y>>z;
		a[x][y]=z;
		a[y][x]=z;
	}
	int maxx=0;
	for(int i=1;i<=n;i++){
		maxx=max(maxx,dfs(i,0));
	}
	cout<<maxx;
}
